// Honest attempt: the postcondition requires `r1->Some_0 == r2->Some_0`
    // (Verus spec equality on `Vec<u8>`), but the hypothesis only gives
    // sequence-level (view) equality.  Verus does NOT include an axiom
    // `v1@ == v2@ ==> v1 == v2` for `Vec` (`Vec` is an external opaque
    // wrapper around `alloc::vec::Vec`; its abstract content beyond the
    // view is unspecified, so two values with the same view need not be
    // spec-equal).  Empirically verified with a minimal reproduction:
    // `requires v1@ == v2@ ensures v1 == v2` fails.  The synthetic
    // determinism check is therefore detecting a real gap in the
    // `clone_optional_value` spec, which only guarantees view equality.
    // We still record what IS derivable, without any axiom-bypassing
    // primitives.
    broadcast use vstd::std_specs::vec::group_vec_axioms;
    if (optional_value_view(ov) == optional_value_view(r1))
        && (optional_value_view(ov) == optional_value_view(r2))
    {
        assert(optional_value_view(r1) == optional_value_view(r2));
        match ov {
            Some(_) => {
                assert(r1 is Some);
                assert(r2 is Some);
                assert(r1->Some_0@ == r2->Some_0@);
            }
            None => {
                assert(r1 is None);
                assert(r2 is None);
            }
        }
    }
